const { expect } = require('chai');
const Require = require('../../../../../src/lib/annotations/resources/Require');
const RequireProcessor = require('../../../../../src/lib/processors/resources/RequireProcessor'); // Singleton importieren
const DiContainer = require('../../../../../src/core/DiContainer');

describe('Require Annotation Integration', () => {
  beforeEach(() => {
    DiContainer.reset();
  });

  it('should register Node.js modules in DI container via Qualifier using instance', () => {
    class AppService {
      constructor() {
        this.fs = null;
        this.pathModule = null;
      }
    }

    const instance = new AppService();

    const metas = [
      { annotation: Require, className: 'AppService', classRef: AppService, propertyName: 'fs', args: ['FS', 'fs'], instance },
      { annotation: Require, className: 'AppService', classRef: AppService, propertyName: 'pathModule', args: ['Path', 'path'], instance }
    ];

    // Mock logger that pushes messages into ctx.log array
    const log = [];
    const mockLogger = {
      info: (msg) => log.push(msg),
      warn: (msg) => log.push(msg),
      error: (msg) => log.push(msg)
    };

    const ctx = { 
      container: DiContainer,
      log: mockLogger,
      config: { baseDir: process.cwd() }
    };

    // ⚡ Use the Singleton processor directly, no "new"
    metas.forEach(meta => RequireProcessor.processDI(meta, ctx));

    // Check that modules are registered under qualifiers
    const fsModule = DiContainer.resolveByQualifier('FS');
    const pathModule = DiContainer.resolveByQualifier('Path');

    expect(fsModule).to.equal(require('fs'));
    expect(pathModule).to.equal(require('path'));

    // Instance properties remain null
    expect(instance.fs).to.be.null;
    expect(instance.pathModule).to.be.null;

    // Check logs
  expect(log).to.include("@Require registered: FS → fs");
  expect(log).to.include("@Require registered: Path → path");
  });
});
